import React, { useEffect, useState } from 'react';

function ResultDisplay({ result, previewUrl, onReset }) {
  const [animatedConfidence, setAnimatedConfidence] = useState(0);
  const isReal = result.class === 'Real';
  const confidencePercent = (result.confidence * 100).toFixed(2);

  useEffect(() => {
    const timer = setTimeout(() => {
      setAnimatedConfidence(parseFloat(confidencePercent));
    }, 200);
    return () => clearTimeout(timer);
  }, [confidencePercent]);

  const badgeStyle = {
    '--badge-bg': isReal ? 'var(--accent-emerald-dim)' : 'var(--accent-rose-dim)',
    '--badge-color': isReal ? 'var(--accent-emerald)' : 'var(--accent-rose)',
    '--result-color': isReal ? 'var(--accent-emerald)' : 'var(--accent-rose)',
  };

  return (
    <div className="glass-card">
      <div className="result-container" style={badgeStyle}>
        <div className="result-image-wrapper">
          <img 
            src={previewUrl} 
            alt="Scanned currency" 
            className="result-image"
          />
        </div>

        <div 
          className="result-badge"
          style={badgeStyle}
        >
          {isReal ? (
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" d="M9 12.75L11.25 15 15 9.75M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
            </svg>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 9v3.75m9-.75a9 9 0 11-18 0 9 9 0 0118 0zm-9 3.75h.008v.008H12v-.008z" />
            </svg>
          )}
          Verification Complete
        </div>

        <h2 className={`result-value ${isReal ? 'real' : 'fake'}`}>
          {result.class}
        </h2>

        <p className="result-title">
          {isReal 
            ? 'Currency appears to be authentic' 
            : 'Currency may be counterfeit'}
        </p>

        <div className="confidence-container">
          <div className="confidence-header">
            <span className="confidence-label">Confidence Score</span>
            <span className="confidence-value">{confidencePercent}%</span>
          </div>
          <div className="confidence-bar-bg">
            <div 
              className={`confidence-bar ${isReal ? 'real' : 'fake'}`}
              style={{ width: `${animatedConfidence}%` }}
            ></div>
          </div>
        </div>

        <button className="btn-secondary" onClick={onReset}>
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 12c0-1.232-.046-2.453-.138-3.662a4.006 4.006 0 00-3.7-3.7 48.678 48.678 0 00-7.324 0 4.006 4.006 0 00-3.7 3.7c-.017.22-.032.441-.046.662M19.5 12l3-3m-3 3l-3-3m-12 3c0 1.232.046 2.453.138 3.662a4.006 4.006 0 003.7 3.7 48.656 48.656 0 007.324 0 4.006 4.006 0 003.7-3.7c.017-.22.032-.441.046-.662M4.5 12l3 3m-3-3l-3 3" />
          </svg>
          Scan Another Note
        </button>
      </div>
    </div>
  );
}

export default ResultDisplay;
